// Publication Scheduler & Optimizer
// Analyzes content queue and schedules optimal publishing times

const contentQueue = $input.all();
const now = new Date();

// Brand-specific posting schedules and limits
const brandSchedules = {
  dax_traveler: {
    platforms: {
      instagram: { times: ['08:00', '12:00', '18:00'], dailyLimit: 2, timezone: 'UTC' },
      facebook: { times: ['09:00', '15:00', '20:00'], dailyLimit: 2, timezone: 'UTC' },
      twitter: { times: ['07:00', '11:00', '15:00', '19:00'], dailyLimit: 4, timezone: 'UTC' },
      linkedin: { times: ['08:00', '17:00'], dailyLimit: 1, timezone: 'UTC' },
      tiktok: { times: ['12:00', '18:00', '21:00'], dailyLimit: 2, timezone: 'UTC' }
    },
    enabled: $env.BRAND_DAX_TRAVELER_ENABLED === 'true'
  },
  timezone_travelers: {
    platforms: {
      instagram: { times: ['10:00', '14:00', '19:00'], dailyLimit: 2, timezone: 'UTC' },
      facebook: { times: ['11:00', '16:00'], dailyLimit: 1, timezone: 'UTC' },
      twitter: { times: ['08:00', '12:00', '16:00', '20:00'], dailyLimit: 3, timezone: 'UTC' },
      pinterest: { times: ['09:00', '13:00', '17:00'], dailyLimit: 3, timezone: 'UTC' }
    },
    enabled: $env.BRAND_TIMEZONE_TRAVELERS_ENABLED === 'true'
  },
  gods_vessel: {
    platforms: {
      instagram: { times: ['06:00', '12:00', '18:00'], dailyLimit: 2, timezone: 'UTC' },
      facebook: { times: ['07:00', '19:00'], dailyLimit: 2, timezone: 'UTC' },
      twitter: { times: ['06:00', '12:00', '18:00'], dailyLimit: 3, timezone: 'UTC' },
      pinterest: { times: ['08:00', '14:00', '20:00'], dailyLimit: 2, timezone: 'UTC' }
    },
    enabled: $env.BRAND_GODS_VESSEL_ENABLED === 'true'
  },
  ani_dax: {
    platforms: {
      instagram: { times: ['14:00', '20:00', '22:00'], dailyLimit: 2, timezone: 'UTC' },
      facebook: { times: ['15:00', '21:00'], dailyLimit: 1, timezone: 'UTC' },
      twitter: { times: ['13:00', '17:00', '21:00'], dailyLimit: 3, timezone: 'UTC' },
      tiktok: { times: ['16:00', '20:00', '23:00'], dailyLimit: 2, timezone: 'UTC' },
      reddit: { times: ['19:00', '22:00'], dailyLimit: 1, timezone: 'UTC' }
    },
    enabled: $env.BRAND_ANI_DAX_ENABLED === 'true'
  }
};

// Filter content ready for publishing
const readyContent = contentQueue.filter(item => 
  item.ready_for_publishing === true && 
  item.status === 'generated' && 
  !item.scheduled_time
);

if (readyContent.length === 0) {
  return { message: 'No content ready for scheduling', scheduledCount: 0 };
}

// Get today's already scheduled posts to respect daily limits
const today = now.toISOString().split('T')[0];
const todayScheduled = contentQueue.filter(item => 
  item.scheduled_time && 
  item.scheduled_time.startsWith(today)
);

// Count scheduled posts by brand and platform for today
const todayCounts = {};
todayScheduled.forEach(item => {
  const key = `${item.brand}_${item.platform}`;
  todayCounts[key] = (todayCounts[key] || 0) + 1;
});

// Schedule content based on optimal times and limits
const scheduledContent = [];

readyContent.forEach(content => {
  const brand = content.brand;
  const platform = content.platform;

  if (!brandSchedules[brand] || !brandSchedules[brand].enabled) {
    return;
  }

  const platformConfig = brandSchedules[brand].platforms[platform];
  if (!platformConfig) {
    return;
  }

  const countKey = `${brand}_${platform}`;
  const currentCount = todayCounts[countKey] || 0;

  if (currentCount >= platformConfig.dailyLimit) {
    return; // Daily limit reached
  }

  // Find next available time slot
  const availableTimes = platformConfig.times;
  let scheduledTime = null;

  for (const timeSlot of availableTimes) {
    const [hours, minutes] = timeSlot.split(':').map(Number);
    const candidateTime = new Date(now);
    candidateTime.setHours(hours, minutes, 0, 0);

    // If time has passed today, schedule for tomorrow
    if (candidateTime <= now) {
      candidateTime.setDate(candidateTime.getDate() + 1);
    }

    // Check if this time slot is already taken
    const timeString = candidateTime.toISOString();
    const isSlotTaken = scheduledContent.some(item => 
      item.scheduled_time === timeString && 
      item.brand === brand && 
      item.platform === platform
    );

    if (!isSlotTaken) {
      scheduledTime = timeString;
      break;
    }
  }

  if (scheduledTime) {
    scheduledContent.push({
      ...content,
      scheduled_time: scheduledTime,
      status: 'scheduled'
    });

    // Update count for this brand/platform
    todayCounts[countKey] = currentCount + 1;
  }
});

return {
  scheduledContent,
  scheduledCount: scheduledContent.length,
  totalReady: readyContent.length,
  timestamp: now.toISOString()
};
